  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE=]') || TO_CLOB(q'['MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='13'
       THEN 'RP'
       ELSE ''
       END
  ||CASE WHEN CASE WHEN TIPO_COMPROBPP.CLASE='ICA'        THEN '7'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='MIC' OR TIPO_COMPROBPP.CLASE='DIC' OR TIPO_COMPROBPP.CLASE='AIC'        THEN '8'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '10'        ELSE ''        END||   CASE WHEN TIPO_COMPROBPP.CLASE='ING' AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '13'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES NOT IN (0)        THEN '15'        ELSE ''        END||   CASE WHEN (TIPO_COMPROBPP.CLASE='MIN' OR TIPO_COMPROBPP.CLASE='DIN' OR TIPO_COMPROBPP.CLASE='AIN') AND COMPROBANTE_PPTAL.PAPELES IN (0)        THEN '11'        ELSE ''        END='15'
       THEN 'OC'
       ELSE ''
       END) IS NOT NULL 
       
